// BlockEntityType returns the block_entity_type id for a block state and whether
// the block has a block entity at all.
func BlockEntityType(state uint32) (int32, bool) {
	lo, hi := 0, len(blockEntityRanges)-1
	for lo <= hi {
		mid := (lo + hi) / 2
		r := blockEntityRanges[mid]
		switch {
		case state < r.Min:
			hi = mid - 1
		case state > r.Max:
			lo = mid + 1
		default:
			return r.Type, true
		}
	}
	return 0, false
}
